export const STICKERS: StickerEntry[] = E;

export const STICKERS_BY_ID: Record<string, StickerEntry> = Object.fromEntries(
  E.map((s) => [s.id, s])
);

export const STICKERS_BY_CATEGORY: Record<StickerCategory, StickerEntry[]> = {
  drinks: E.filter((s) => s.category === 'drinks'),
  food: E.filter((s) => s.category === 'food'),
  retail: E.filter((s) => s.category === 'retail'),
  service: E.filter((s) => s.category === 'service'),
};

export function getStickerXml(id: string): string | null {
  return STICKERS_BY_ID[id]?.xml ?? null;
}
